"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["9911"],{9641(e,n,i){i.r(n),i.d(n,{metadata:()=>o,default:()=>p,frontMatter:()=>t,contentTitle:()=>s,toc:()=>l,assets:()=>c});var o=JSON.parse('{"id":"Planets & Points/mercury","title":"mercury","description":"MERCURY","source":"@site/docs/Planets & Points/mercury.md","sourceDirName":"Planets & Points","slug":"/Planets & Points/mercury","permalink":"/Planets & Points/mercury","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Planets & Points/mercury.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Venus","permalink":"/Planets & Points/Venus"},"next":{"title":"node","permalink":"/Planets & Points/node"}}'),a=i(4848),r=i(8453);let t={},s,c={},l=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function d(e){let n={h3:"h3",li:"li",p:"p",ul:"ul",...(0,r.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.p,{children:"MERCURY"}),"\n",(0,a.jsx)(n.p,{children:"Principle:"}),"\n",(0,a.jsx)(n.p,{children:"Intellect, mediation"}),"\n",(0,a.jsx)(n.p,{children:"Psychological Correspondence:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Good grasp or understanding of a subject, sound judgement, critical ability, dexterity in expression and in writing, mediation, diplomacy, general intellectual abilities, analysis."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"A lack of understanding and of objective criticism, the tendency to diffuse one's energy into too many channels, inhibitions in speech and in writing, overdevelopment or weakness of intellect."}),"\n"]}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"Biological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"The motor-nerves (speech- and hearing organs)"}),"\n",(0,a.jsx)(n.p,{children:"Sociological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"Intellectual workers, tradesmen, agents or mediators."}),"\n",(0,a.jsx)(n.p,{children:"Position in Houses and Signs:"}),"\n",(0,a.jsx)(n.p,{children:"I. Mental activity, a constructive intellect, creative thinking, keen powers of observation, criticism, enthusiasm, quickness at repartee in speech and writing, rashness, exaggeration, mental overworking. \u2013 Nervousness."}),"\n",(0,a.jsx)(n.p,{children:"II. Logical thinking, formal thinking, logic, endurance and patience in relation to mental activity, a sense of form, deliberation. \u2013 One-sided views. \u2013 Hoarseness caused by too much talking."}),"\n",(0,a.jsx)(n.p,{children:"III. Versatile thinking, love of variety and change, adaptability, business talent. \u2013 Lack of constancy, honesty, tidiness. \u2013 Active or lively correspondence."}),"\n",(0,a.jsx)(n.p,{children:"IV. Perception, inter-relationship between thinking and feeling, a good memory, the tendency to become deeply immersed in something, positive or constructive criticism, one's own individual methods of work, a sense of harmony, art interests."}),"\n",(0,a.jsx)(n.p,{children:"V. Creative thinking, the power of enthusiasm, a wealth of plans, organising ability, prudence, far-sightedness, speculation, the desire for possessions. \u2013 Intellectual leaders, organisers, speculators."}),"\n",(0,a.jsx)(n.p,{children:"VI. The thirst for knowledge, practical thinking, patience, well-grounded expert-knowledge and specialised skill, little ability to comprehend the whole. \u2013 Tidiness, care and attention, criticism. \u2013 Nervous disturbances of the digestive tract owing to a sedentary mode of living. Good collaboration and cooperation, also team-work."}),"\n",(0,a.jsx)(n.p,{children:"VII. Creative thinking within patterns already in existence, team-work, adaptability, good powers of comparison, a sense of justice, a sense of form and beauty, good manners, tactful mediation."}),"\n",(0,a.jsx)(n.p,{children:"VIII. Sharp criticism, fanaticism, endurance and perseverance in the pursuit of difficult problems and in the solution of arduous tasks, practical ability. \u2013 Sarcasm, scepticism, cunning and craft. \u2013 Lively disputes, arguments, fights."}),"\n",(0,a.jsx)(n.p,{children:"IX. Deep thinking coupled with social or religious tendencies, the philosopher, manifold interests, a striving for justice and truth, occupation with the problems of life. \u2013 The danger of scattering one's energies. \u2013 The tendency to evade difficult tasks or to take the line of least resistance."}),"\n",(0,a.jsx)(n.p,{children:"X. Concentration, thoroughness, endurance, patience, consciousness of aim or objective, logic, the tendency to view life seriously, the solution of difficult problems. \u2013 Melancholy, (shrewd) cunning, craftiness. \u2013 Success through one's own merit, economy, reserve. Ambition is often the driving force behind all activity."}),"\n",(0,a.jsx)(n.p,{children:"XI. Progressive thinking, interest in inventions and in reforms, a wealth of plans, the quick grasp of a situation, individual and original judgement, creative thinking, enthusiasm. \u2013 Utopian ideas, the tendency to revel, the desire to work alone. Organisers, reformers, inventors."}),"\n",(0,a.jsx)(n.p,{children:"XII. A person who is easily influenced in his or her thoughts by others, a receptiveness for the thoughts of others, the ability to reproduce, phantasy and imagination. \u2013 Planning without energy of action, philosophical ideas."}),"\n",(0,a.jsx)(n.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,a.jsx)(n.p,{children:"MERKURY"}),"\n",(0,a.jsx)(n.p,{children:"Zasada:"}),"\n",(0,a.jsx)(n.p,{children:"Intelekt, po\u015Brednictwo"}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Dobre poj\u0119cie lub zrozumienie zagadnienia, rozs\u0105dny os\u0105d, zdolno\u015B\u0107 krytyczna, zr\u0119czno\u015B\u0107 w wypowiedzi i w pi\u015Bmie, po\u015Brednictwo, dyplomacja, og\xf3lne zdolno\u015Bci intelektualne, analiza."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Brak zrozumienia i obiektywnej krytyki, tendencja do rozpraszania energii na zbyt wiele kana\u0142\xf3w, zahamowania w mowie i w pi\u015Bmie, nadmierny rozw\xf3j lub s\u0142abo\u015B\u0107 intelektu."}),"\n"]}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja biologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Nerwy ruchowe (narz\u0105dy mowy i s\u0142uchu)"}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Pracownicy umys\u0142owi, handlowcy, agenci lub po\u015Brednicy."}),"\n",(0,a.jsx)(n.p,{children:"Pozycja w domach i znakach:"}),"\n",(0,a.jsx)(n.p,{children:"I. Aktywno\u015B\u0107 umys\u0142owa, konstruktywny intelekt, kreatywne my\u015Blenie, bystra zdolno\u015B\u0107 obserwacji, krytycyzm, entuzjazm, szybko\u015B\u0107 riposty w mowie i pi\u015Bmie, lekkomy\u015Blno\u015B\u0107, przesada, przepracowanie umys\u0142owe. \u2013 Nerwowo\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"II. Logiczne my\u015Blenie, formalne my\u015Blenie, logika, wytrwa\u0142o\u015B\u0107 i cierpliwo\u015B\u0107 w odniesieniu do aktywno\u015Bci umys\u0142owej, zmys\u0142 formy, rozwaga. \u2013 Jednostronne pogl\u0105dy. \u2013 Chrypka spowodowana zbyt g\u0142o\u015Bnym m\xf3wieniem."}),"\n",(0,a.jsx)(n.p,{children:"III. Wszechstronne my\u015Blenie, zami\u0142owanie do r\xf3\u017Cnorodno\u015Bci i zmian, zdolno\u015B\u0107 adaptacji, talent biznesowy. \u2013 Brak sta\u0142o\u015Bci, uczciwo\u015Bci, porz\u0105dku. \u2013 Aktywna lub \u017Cywa korespondencja."}),"\n",(0,a.jsx)(n.p,{children:"IV. Percepcja, wzajemna zale\u017Cno\u015B\u0107 mi\u0119dzy my\u015Bleniem a odczuwaniem, dobra pami\u0119\u0107, tendencja do g\u0142\u0119bokiego zanurzania si\u0119 w co\u015B, pozytywna lub konstruktywna krytyka, w\u0142asne, indywidualne metody pracy, zmys\u0142 harmonii, zainteresowania artystyczne."}),"\n",(0,a.jsx)(n.p,{children:"V. Kreatywne my\u015Blenie, si\u0142a entuzjazmu, bogactwo plan\xf3w, zdolno\u015Bci organizacyjne, roztropno\u015B\u0107, dalekowzroczno\u015B\u0107, spekulacja, pragnienie posiadania. \u2013 Liderzy intelektualni, organizatorzy, spekulanci."}),"\n",(0,a.jsx)(n.p,{children:"VI. Pragnienie wiedzy, praktyczne my\u015Blenie, cierpliwo\u015B\u0107, ugruntowana wiedza ekspercka i specjalistyczne umiej\u0119tno\u015Bci, niewielka zdolno\u015B\u0107 pojmowania ca\u0142o\u015Bci. \u2013 Porz\u0105dek, troska i uwaga, krytycyzm. \u2013 Zaburzenia nerwowe przewodu pokarmowego z powodu siedz\u0105cego trybu \u017Cycia. Dobra kolaboracja i wsp\xf3\u0142praca, a tak\u017Ce praca zespo\u0142owa."}),"\n",(0,a.jsx)(n.p,{children:"VII. Kreatywne my\u015Blenie w ramach ju\u017C istniej\u0105cych wzorc\xf3w, praca zespo\u0142owa, zdolno\u015B\u0107 adaptacji, dobre zdolno\u015Bci por\xf3wnawcze, zmys\u0142 sprawiedliwo\u015Bci, zmys\u0142 formy i pi\u0119kna, dobre maniery, taktowne po\u015Brednictwo."}),"\n",(0,a.jsx)(n.p,{children:"VIII. Ostra krytyka, fanatyzm, wytrwa\u0142o\u015B\u0107 i uporczywo\u015B\u0107 w d\u0105\u017Ceniu do trudnych problem\xf3w i w rozwi\u0105zywaniu \u017Cmudnych zada\u0144, praktyczne zdolno\u015Bci. \u2013 Sarkazm, sceptycyzm, przebieg\u0142o\u015B\u0107 i kunszt (podst\u0119p). \u2013 \u017Bywe spory, argumenty, walki."}),"\n",(0,a.jsx)(n.p,{children:"IX. G\u0142\u0119bokie my\u015Blenie po\u0142\u0105czone z tendencjami spo\u0142ecznymi lub religijnymi, filozof, r\xf3\u017Cnorodne zainteresowania, d\u0105\u017Cenie do sprawiedliwo\u015Bci i prawdy, zajmowanie si\u0119 problemami \u017Cycia. \u2013 Niebezpiecze\u0144stwo rozproszenia w\u0142asnej energii. \u2013 Tendencja do unikania trudnych zada\u0144 lub wybierania linii najmniejszego oporu."}),"\n",(0,a.jsx)(n.p,{children:"X. Koncentracja, dok\u0142adno\u015B\u0107, wytrwa\u0142o\u015B\u0107, cierpliwo\u015B\u0107, \u015Bwiadomo\u015B\u0107 celu lub d\u0105\u017Cenia, logika, tendencja do powa\u017Cnego traktowania \u017Cycia, rozwi\u0105zywanie trudnych problem\xf3w. \u2013 Melancholia, (bystra) przebieg\u0142o\u015B\u0107, chytro\u015B\u0107. \u2013 Sukces dzi\u0119ki w\u0142asnym zas\u0142ugom, oszcz\u0119dno\u015B\u0107, rezerwa. Ambicja jest cz\u0119sto si\u0142\u0105 nap\u0119dow\u0105 wszelkiej aktywno\u015Bci."}),"\n",(0,a.jsx)(n.p,{children:"XI. Post\u0119powe my\u015Blenie, zainteresowanie wynalazkami i reformami, bogactwo plan\xf3w, szybkie zrozumienie sytuacji, indywidualny i oryginalny os\u0105d, kreatywne my\u015Blenie, entuzjazm. \u2013 Idee utopijne, tendencja do biesiadowania (p\u0142awienia si\u0119 w czym\u015B), pragnienie samodzielnej pracy. Organizatorzy, reformatorzy, wynalazcy."}),"\n",(0,a.jsx)(n.p,{children:"XII. Osoba, na kt\xf3rej my\u015Bli inni \u0142atwo wywieraj\u0105 wp\u0142yw, receptywno\u015B\u0107 na my\u015Bli innych, zdolno\u015B\u0107 do reprodukowania, fantazja i wyobra\u017Ania. \u2013 Planowanie bez energii do dzia\u0142ania, idee filozoficzne."})]})}function p(e={}){let{wrapper:n}={...(0,r.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},8453(e,n,i){i.d(n,{R:()=>t,x:()=>s});var o=i(6540);let a={},r=o.createContext(a);function t(e){let n=o.useContext(r);return o.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function s(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:t(e.components),o.createElement(r.Provider,{value:n},e.children)}}}]);